let topic = '금리 동결 이후 재테크 전략';
let durationMinutes = 8;
let targetAudience = '시니어';
let platform = 'youtube';
let targetFormat = 'longform';
let category = 'video';
let intent = 'longform_video';
let keywords = [];
let references = [];
try {
  const wh = $('Webhook 수신').all();
  if (wh.length) {
    const raw = wh[0].json;
    const b = raw.body ?? raw;
    const parsed = typeof b === 'string' ? JSON.parse(b) : b;
    if (parsed?.topic) topic = String(parsed.topic);
    if (parsed?.durationMinutes != null) durationMinutes = Number(parsed.durationMinutes) || 8;
    if (parsed?.targetAudience) targetAudience = String(parsed.targetAudience);
    if (parsed?.platform) platform = String(parsed.platform);
    if (parsed?.targetFormat) targetFormat = String(parsed.targetFormat);
    if (parsed?.category) category = String(parsed.category);
    if (parsed?.intent) intent = String(parsed.intent);
    if (Array.isArray(parsed?.keywords)) keywords = parsed.keywords.map(String);
    if (Array.isArray(parsed?.references)) references = parsed.references;
  }
} catch {}
if (!Number.isFinite(durationMinutes) || durationMinutes < 2) durationMinutes = targetFormat === 'longform' ? 8 : 0;
return [{ json: { topic, durationMinutes, targetAudience, platform, targetFormat, category, intent, keywords, references, source: 'n8n' } }];

const params = $input.first().json;

const refLines = (params.references || []).slice(0, 10).map((r, i) => {
  const meta = [r.platform, r.channel, r.vsAvg != null ? `vs.Avg ${r.vsAvg}x` : null].filter(Boolean).join(' · ');
  return `${i + 1}. ${r.title}${meta ? ` (${meta})` : ''}`;
}).join('\n') || '없음';
const refBlock = (params.references || []).length
  ? `\n\n[참고 레퍼런스(선택) — 제목·구조·톤만 벤치마킹, 문장 복사·주제 변경 금지]\n${refLines}`
  : '\n\n[참고 레퍼런스 없음 — 주제 키워드만으로 작성]';
const kwLine = (params.keywords || []).length ? `\n보조 키워드: ${params.keywords.join(', ')}` : '';
const fmt = params.targetFormat || 'longform';
const chapterCount = Math.max(4, Math.min(8, Math.floor(((params.durationMinutes || 8) - 1) / 1.2)));

let role, jsonSchema, extra, maxTokens;

if (fmt === 'shortform') {
  role = 'YouTube Shorts·Reels 숏폼 스크립터';
  jsonSchema = `{
  "title": "영상 제목 (30자 이내, 클릭 유도)",
  "hook": "0~3초 오프닝 훅 1~2문장 (숫자·반전·질문)",
  "chapters": [
    { "heading": "씬1 · 0~10초", "durationSec": 10, "bullets": ["나레이션 핵심"] }
  ],
  "cta": "마지막 2초 CTA (구독·저장·댓글)",
  "seoKeywords": ["해시태그1", "해시태그2"],
  "fullScript": "[0~10초]\\n나레이션: ...\\n화면(한글): ...\\n자막: ...",
  "flowPasteBlock": "Scene 1 (0-10s): [Subject] ... [Action] ... [Camera] ... [Lighting] ... 9:16 safe-zone"
}`;
  extra = `- 총 길이 45~60초, 씬 3~5개
- chapters는 씬별로 heading에 "씬N · 시작초~끝초" 형식
- fullScript: 씬마다 [0~N초] 헤더 + 나레이션(한글) + 화면(한글) + 자막 + 제작 메모
- flowPasteBlock: 씬별 영문 Higgsfield/Google Flow 프롬프트 (피사체·행동·카메라·조명·무드·9:16 안전영역 포함), 씬 구분은 "### 씬N · 시작~끝초" 헤더로
- **주제(필수)** 줄의 주제만 사용, 레퍼런스 주제·문장 복사 금지`;
  maxTokens = 3000;
} else if (fmt === 'blog') {
  role = '네이버·티스토리 SEO 블로그 전문 작가';
  jsonSchema = `{
  "title": "검색 친화 제목",
  "hook": "첫 2문단 요약",
  "chapters": [{ "heading": "H2 소제목", "durationSec": 0, "bullets": ["문단 핵심"] }],
  "cta": "마무리 CTA",
  "seoKeywords": ["키워드"],
  "fullScript": "마크다운 전체 블로그 본문 (H2·표·이미지 가이드 블록 포함)"
}`;
  extra = `- chapters는 H2 소제목 4~6개
- fullScript는 1500자 이상 완성 블로그
- 제목 공식: 숫자형·질문형·대비형 중 1개 적용`;
  maxTokens = 4096;
} else if (fmt === 'carousel') {
  role = '인스타그램 캐러셀 카드뉴스 기획자';
  jsonSchema = `{
  "title": "시리즈 제목 (20자 이내)",
  "hook": "1장 후킹 문구 (저장 유도)",
  "chapters": [
    { "heading": "슬라이드1: 표지", "durationSec": 0, "bullets": ["핵심 문구"] },
    { "heading": "슬라이드2: 본문1", "durationSec": 0, "bullets": ["팁 1줄"] }
  ],
  "cta": "마지막 슬라이드 CTA + 해시태그 5개",
  "seoKeywords": ["#해시태그1", "#해시태그2"],
  "fullScript": "## 슬라이드 1: 표지\\n본문 카피 (40자 이내)\\n\\n## 슬라이드 2\\n..."
}`;
  extra = `- chapters는 슬라이드 7~10장 (저장율 최적)
- fullScript: 슬라이드마다 ## 슬라이드 N: 제목 + 카피(40자 이내) + 배경 이미지 키워드(영문)
- 1장(표지)·중간(팁·데이터)·마지막(CTA) 구조 필수
- 정보형·감성형·체크리스트형 중 주제에 맞는 톤 선택`;
  maxTokens = 3000;
} else {
  // longform (default)
  role = '유튜브 롱폼 콘텐츠 전문 스크립터';
  jsonSchema = `{
  "title": "시청자가 클릭하고 싶은 제목 (30자 이내)",
  "hook": "오프닝 훅 2~3문장 (결론 미리보기 또는 수치 공개)",
  "chapters": [
    { "heading": "챕터 제목", "durationSec": 90, "bullets": ["핵심 포인트 1", "핵심 포인트 2"] }
  ],
  "cta": "마지막 1분 CTA + 다음 영상 예고",
  "seoKeywords": ["키워드"],
  "fullScript": "# 제목\\n\\n## 오프닝 훅 (0~30초)\\n...\\n\\n## 챕터1 제목 (00:30)\\n..."
}`;
  extra = `- chapters는 정확히 ${chapterCount}개 (챕터당 약 1~1.5분)
- 각 chapter.durationSec은 실제 분량(초) 명시
- fullScript: H2 헤더에 타임스탬프 "(MM:SS)" 포함, 촬영용 완성 대본
- 서론 10% · 본론 75% · 결론+CTA 15% 비율 유지`;
  maxTokens = 6000;
}

const durationLine = fmt === 'longform'
  ? `목표 길이: 약 ${params.durationMinutes || 8}분 (총 ${(params.durationMinutes || 8) * 60}초)\n`
  : '';

const prompt = `당신은 ${params.targetAudience || '일반'} 타겟 ${role}입니다.
주제(필수): ${params.topic}
포맷: ${fmt} · 플랫폼: ${params.platform || 'youtube'}
${durationLine}${refBlock}${kwLine}

아래 JSON만 응답 (마크다운 코드블록 없이 순수 JSON):
${jsonSchema}

조건:
${extra}
- **주제·본문은 반드시 위 «주제(필수)» 줄만 따름** — 레퍼런스와 다른 주제로 작성 금지
- 참고 레퍼런스가 있으면 제목·구조·톤만 벤치마킹, 문장 복사·주제 변경 금지
- 레퍼런스 없으면 주제 키워드와 일반 지식으로 오리지널 작성`;

return [{ json: { ...params, geminiPrompt: prompt, chapterCount, targetFormat: fmt, maxTokens } }];

const params = $('Gemini 프롬프트 준비').first().json;
const geminiRaw = $input.first().json;

let script = null;
try {
  const text = geminiRaw?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) script = JSON.parse(jsonMatch[0]);
} catch(e) { /* 파싱 실패 → 폴백 */ }

const fmt = params.targetFormat || 'longform';

if (!script || !script.title) {
  const dur = params.durationMinutes || 8;
  if (fmt === 'shortform') {
    script = {
      title: `${params.topic} 숏폼`,
      hook: `오늘은 '${params.topic}'에 대해 딱 1분만 정리해 드립니다.`,
      chapters: [
        { heading: '씬1 · 0~5초', durationSec: 5, bullets: ['오프닝 훅'] },
        { heading: '씬2 · 5~40초', durationSec: 35, bullets: ['핵심 내용'] },
        { heading: '씬3 · 40~55초', durationSec: 15, bullets: ['마무리'] },
      ],
      cta: '구독하고 더 많은 정보 받아가세요!',
      seoKeywords: [params.topic, '숏폼', '정보'],
      fullScript: `[0~5초]\n나레이션: ${params.topic}, 딱 1분만 보세요.\n화면(한글): 텍스트 훅 화면\n자막: ${params.topic}\n\n[5~40초]\n나레이션: (핵심 내용을 직접 작성해주세요)\n화면(한글): 관련 배경 화면\n자막: 핵심 키워드\n\n[40~55초]\n나레이션: 도움이 됐다면 구독 부탁드립니다.\n화면(한글): 아웃트로 화면\n자막: 구독 CTA`,
      flowPasteBlock: `### 씬1 · 0~5초\nA close-up of bold text appearing on screen saying "${params.topic}", modern minimal style, 9:16 vertical safe-zone, soft studio lighting, camera slow zoom in.\n\n### 씬2 · 5~40초\nA person explaining information with gestures, clean background, warm lighting, 9:16 vertical, camera steady medium shot.\n\n### 씬3 · 40~55초\nSubscribe button animation with upbeat vibe, 9:16 vertical safe-zone, bright energetic lighting.`,
    };
  } else if (fmt === 'carousel') {
    script = {
      title: `${params.topic} 카드뉴스`,
      hook: `알고 계셨나요? ${params.topic}에 대한 핵심만 모았습니다 👇`,
      chapters: Array.from({length: 7}, (_, i) => ({
        heading: `슬라이드${i+1}`, durationSec: 0,
        bullets: [i === 0 ? '표지' : i === 6 ? 'CTA' : `팁 ${i}`]
      })),
      cta: '저장해두고 나중에 활용하세요! #정보 #꿀팁',
      seoKeywords: [`#${params.topic}`, '#정보', '#꿀팁', '#카드뉴스', '#인스타'],
      fullScript: `## 슬라이드 1: 표지\n${params.topic}\n알아두면 인생이 달라지는 정보\n*Background: minimal gradient, bold typography*\n\n## 슬라이드 2\n(내용을 직접 작성해주세요)\n*Background keyword: clean infographic style*\n\n## 슬라이드 7: CTA\n저장하고 나중에 다시 보세요!\n팔로우하면 더 많은 정보를 드립니다 😊`,
    };
  } else if (fmt === 'blog') {
    script = {
      title: `${params.topic} 완벽 가이드`,
      hook: `오늘은 '${params.topic}'에 대해 상세히 알아보겠습니다.`,
      chapters: [
        { heading: '개요', durationSec: 0, bullets: ['배경', '왜 중요한가'] },
        { heading: '핵심 내용', durationSec: 0, bullets: ['포인트 1', '포인트 2'] },
        { heading: '마무리', durationSec: 0, bullets: ['요약', '실천 팁'] },
      ],
      cta: '도움이 됐다면 구독 부탁드립니다.',
      seoKeywords: [params.topic, '가이드', '정보'],
      fullScript: `# ${params.topic} 완벽 가이드\n\n오늘은 '${params.topic}'에 대해 이야기해 보겠습니다.\n\n## 개요\n(내용을 직접 작성해주세요)\n\n## 핵심 내용\n(내용을 직접 작성해주세요)\n\n## 마무리\n(내용을 직접 작성해주세요)`,
    };
  } else {
    script = {
      title: `[시니어] ${params.topic}`,
      hook: `오늘은 '${params.topic}'에 대해 이야기해 볼게요. 이 영상 끝까지 보시면 바로 써먹을 수 있는 방법을 드립니다.`,
      chapters: [
        { heading: '배경과 현황', durationSec: Math.round(dur * 60 * 0.25), bullets: ['현재 상황 설명', '왜 중요한가', '많이 하는 오해'] },
        { heading: '핵심 전략', durationSec: Math.round(dur * 60 * 0.4), bullets: ['전략 1', '전략 2', '전략 3'] },
        { heading: '주의사항과 마무리', durationSec: Math.round(dur * 60 * 0.2), bullets: ['놓치기 쉬운 포인트', '실천 체크리스트'] },
      ],
      cta: '도움이 되셨다면 구독과 좋아요 부탁드립니다. 다음 영상에서는 더 자세한 내용으로 찾아뵐게요.',
      seoKeywords: [params.topic, '시니어', '재테크', '노후준비', '경제'],
      fullScript: `# ${params.topic}\n\n## 오프닝 (00:00)\n오늘은 '${params.topic}'에 대해 이야기해 볼게요.\n\n(이하 내용을 직접 작성해주세요)`,
    };
  }
}

// chapterMarkers: chapters[]에서 누적 타임스탬프 계산
let chapterMarkers = [];
if (Array.isArray(script.chapters) && fmt !== 'shortform' && fmt !== 'carousel') {
  let elapsed = 0;
  chapterMarkers = script.chapters
    .filter(c => c.heading)
    .map(c => {
      const mm = String(Math.floor(elapsed / 60)).padStart(2, '0');
      const ss = String(elapsed % 60).padStart(2, '0');
      const marker = { timestamp: `${mm}:${ss}`, title: String(c.heading), durationSec: c.durationSec };
      elapsed += c.durationSec || 90;
      return marker;
    });
}

const now = new Date().toISOString();
return [{ json: {
  ok: true,
  mode: 'n8n',
  topic: params.topic,
  targetFormat: params.targetFormat || 'longform',
  durationMinutes: params.durationMinutes,
  targetAudience: params.targetAudience,
  aiEnhanced: !!geminiRaw?.candidates?.[0],
  script: { ...script, chapterMarkers: chapterMarkers.length > 0 ? chapterMarkers : undefined },
  generatedAt: now,
  message: `'${params.topic}' ${fmt} 스크립트 생성 완료`,
} }];

const params = $input.first().json;
const dur = params.durationMinutes || 8;
const fmt = params.targetFormat || 'longform';

let script;
if (fmt === 'shortform') {
  script = {
    title: `${params.topic} 숏폼`,
    hook: `오늘은 '${params.topic}' 딱 1분!`,
    chapters: [
      { heading: '씬1 · 0~5초', durationSec: 5, bullets: ['훅'] },
      { heading: '씬2 · 5~50초', durationSec: 45, bullets: ['본문'] },
      { heading: '씬3 · 50~60초', durationSec: 10, bullets: ['CTA'] },
    ],
    cta: '구독 부탁드립니다!',
    seoKeywords: [params.topic, '숏폼'],
    fullScript: `[0~5초]\n나레이션: ${params.topic}, 1분 요약!\n화면(한글): 텍스트 훅\n\n[5~50초]\n나레이션: (GEMINI_API_KEY 미설정 — 직접 작성)\n화면(한글): 관련 장면\n\n[50~60초]\n나레이션: 도움 됐다면 구독!\n화면(한글): 아웃트로`,
    flowPasteBlock: `### 씬1 · 0~5초\nBold text "${params.topic}" appears on dark minimal background, 9:16 vertical, slow zoom in.\n\n### 씬2 · 5~50초\nPerson explaining with gestures, clean studio background, 9:16 vertical, medium shot.\n\n### 씬3 · 50~60초\nSubscribe CTA animation, bright energetic, 9:16 vertical.`,
  };
} else if (fmt === 'carousel') {
  script = {
    title: `${params.topic} 카드뉴스`,
    hook: `${params.topic} 핵심 정리 👇`,
    chapters: Array.from({length: 7}, (_, i) => ({ heading: `슬라이드${i+1}`, durationSec: 0, bullets: [`내용 ${i+1}`] })),
    cta: '저장 & 팔로우!',
    seoKeywords: [`#${params.topic}`, '#정보', '#꿀팁', '#카드뉴스', '#인스타'],
    fullScript: `## 슬라이드 1: 표지\n${params.topic}\n\n## 슬라이드 2~6\n(GEMINI_API_KEY 미설정 — 직접 작성)\n\n## 슬라이드 7: CTA\n저장하고 팔로우!`,
  };
} else {
  script = {
    title: `[시니어] ${params.topic}`,
    hook: `오늘 주제는 '${params.topic}'입니다. 끝까지 보시면 실생활에 바로 쓸 수 있는 팁을 드립니다.`,
    chapters: [
      { heading: '배경과 현황', durationSec: Math.round(dur * 60 * 0.25), bullets: ['현재 상황', '왜 중요한가', '오해와 진실'] },
      { heading: '핵심 포인트 3가지', durationSec: Math.round(dur * 60 * 0.4), bullets: ['첫 번째 포인트', '두 번째 포인트', '세 번째 포인트'] },
      { heading: '마무리와 실천법', durationSec: Math.round(dur * 60 * 0.2), bullets: ['오늘 당장 할 수 있는 것', '체크리스트'] },
    ],
    cta: '구독과 좋아요로 응원해 주세요. 다음 영상에서 더 유익한 내용으로 만나요.',
    seoKeywords: [params.topic, '시니어', '노후', '재테크', '경제'],
    fullScript: `# ${params.topic}\n\n## 오프닝 훅 (00:00)\n(GEMINI_API_KEY 미설정 — 직접 작성해주세요)\n\n## 본문\n각 챕터 내용을 채워주세요.`,
  };
}

return [{ json: {
  ok: true,
  mode: 'fallback',
  topic: params.topic,
  targetFormat: fmt,
  durationMinutes: dur,
  targetAudience: params.targetAudience,
  aiEnhanced: false,
  script,
  generatedAt: new Date().toISOString(),
  message: 'GEMINI_API_KEY 미설정 — 기본 구조만 생성됨. .env.local에 키를 추가하면 AI 생성이 활성화됩니다.',
} }];
